<?php
error_reporting(E_ALL);
ini_set('display_errors', 1);

$token = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9..8exo5GDiGezrDJvueNWAX1A70dIFZVxD8eAmz8RPC-g';

// Decode without validation
$parts = explode('.', $token);
echo "<h2>1. Token Structure</h2>";
echo "Parts: " . count($parts) . "<br>";

$header = json_decode(base64_decode(strtr($parts[0], '-_', '+/')), true);
$payload = json_decode(base64_decode(strtr($parts[1], '-_', '+/')), true);

echo "<h2>2. Header</h2>";
echo "<pre>" . print_r($header, true) . "</pre>";

echo "<h2>3. Payload</h2>";
echo "<pre>" . print_r($payload, true) . "</pre>";

echo "<h2>4. Expiration Check</h2>";
$exp = $payload['exp'];
echo "exp: $exp<br>";
echo "now: " . time() . "<br>";
echo "Status: " . ($exp > time() ? "VALID (not expired)" : "EXPIRED") . "<br>";

// Try JWT validation
echo "<h2>5. Signature Validation</h2>";
$secret = 'B7BFCA89BF11459E898B26310C2794E6819FB0AD0565B4C3';
$expectedSig = hash_hmac('sha256', $parts[0] . '.' . $parts[1], $secret, true);
$actualSig = base64_decode(strtr($parts[2], '-_', '+/'));

echo "Secret length: " . strlen($secret) . "<br>";
echo "Signature match: " . (hash_equals($expectedSig, $actualSig) ? "YES" : "NO") . "<br>";
